import{_ as i,c as l,o as e,ae as o}from"./chunks/framework.D4x4JNJ3.js";const m=JSON.parse('{"title":"版本更新日志 v2025.2.x","description":"","frontmatter":{"title":"版本更新日志 v2025.2.x"},"headers":[],"relativePath":"zh/changelog/v2025.2.x.md","filePath":"zh/changelog/v2025.2.x.md","lastUpdated":1772097359000}'),t={name:"zh/changelog/v2025.2.x.md"};function n(r,a,s,d,h,c){return e(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="mogan-stem-v2025-2-x-版本更新日志" tabindex="-1">Mogan STEM v2025.2.x 版本更新日志 <a class="header-anchor" href="#mogan-stem-v2025-2-x-版本更新日志" aria-label="Permalink to “Mogan STEM v2025.2.x 版本更新日志”">​</a></h1><blockquote><p>说明：Liii STEM 是 Mogan STEM 的商业版，会在开源版的基础上提供账号登录、AI 等增值能力。更多细节见Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2025.2.x.html" target="_blank" rel="">v2025.2.x</a></p></blockquote><h2 id="⭐️-全新功能和亮点" tabindex="-1">⭐️ 全新功能和亮点 <a class="header-anchor" href="#⭐️-全新功能和亮点" aria-label="Permalink to “⭐️ 全新功能和亮点”">​</a></h2><ol><li><strong>Python 插件渲染升级</strong>：支持将 Matplotlib 图像、SymPy 公式、Pandas 表格渲染为可编辑内容，并支持插入折叠的可运行代码块。</li><li><strong>结构化搜索与替换</strong>：支持对文本、公式、符号、矩阵等结构内容进行搜索与替换。</li><li><strong>黑夜模式与批注</strong>：界面与文档黑夜模式；批注支持插入、折叠/展开，并支持公式等内容。</li><li><strong>性能与稳定性</strong>：优化数学模式编辑性能；排版引擎优化（中文标点压缩）；修复 Windows 在 125% 缩放等情况下菜单栏消失问题等。</li><li><strong>多标签页置顶</strong>：支持将标签页置顶（类似 Chrome 浏览器体验）。</li><li><strong>矢量图与图片格式</strong>：原生支持 PDF 矢量图；新增 WebP 图片支持。</li><li><strong>插件生态与环境支持</strong>：完善 Python/Maxima/Gnuplot 等插件支持，并支持 conda 环境。</li><li><strong>文档与输入增强</strong>：页码设置更灵活；新增更多符号与 Tab Cycling 输入（<code>\\textendash</code>/<code>\\textemdash</code>、LEGO 符号等）；新增下划线与删除线等。（Liii STEM 另提供 AI、OCR 等增值能力）</li></ol><h2 id="🌟-总结" tabindex="-1">🌟 总结 <a class="header-anchor" href="#🌟-总结" aria-label="Permalink to “🌟 总结”">​</a></h2><p>v2025.2.x 系列聚焦于“可运行插件 + 编辑与排版体验 + 格式支持”的全面提升：Python 插件渲染链路升级让图像/公式/表格可直接编辑，同时补齐 PDF 矢量图与 WebP 等格式能力，并在结构化搜索替换、黑夜模式、批注、中文排版与跨平台稳定性等方面持续迭代。商业版 Liii STEM 会在此基础上提供账号登录、AI、OCR 等增值能力。</p><h2 id="🔧-更新日志" tabindex="-1">🔧 更新日志 <a class="header-anchor" href="#🔧-更新日志" aria-label="Permalink to “🔧 更新日志”">​</a></h2><h3 id="mogan-stem-v2025-2-3-2026-01-06" tabindex="-1">Mogan STEM v2025.2.3 (2026/01/06) <a class="header-anchor" href="#mogan-stem-v2025-2-3-2026-01-06" aria-label="Permalink to “Mogan STEM v2025.2.3 (2026/01/06)”">​</a></h3><ol><li>更现代化的结构化搜索与替换：支持公式、符号、矩阵等结构内容。</li><li>全新黑夜模式：界面与文档均支持黑夜模式。</li><li>全新批注功能：支持插入批注并折叠/展开，批注内容支持公式等。</li><li>排版引擎优化：中文标点压缩。</li><li>Tab Cycling 增强：新增 <code>mathcal</code>/<code>mathbf</code>/<code>mathfrak</code> 输入方式；为 <code>n</code> 增加 <code>\\nabla</code> 变体。</li><li>图片悬浮菜单：支持布局快速调整；（Liii STEM）支持 OCR 识别。</li><li><code>nbsp</code> 显示优化：不换行空格默认采用不可见颜色，可调整。</li></ol><h3 id="mogan-stem-v2025-2-2-2025-12-10" tabindex="-1">Mogan STEM v2025.2.2 (2025/12/10) <a class="header-anchor" href="#mogan-stem-v2025-2-2-2025-12-10" aria-label="Permalink to “Mogan STEM v2025.2.2 (2025/12/10)”">​</a></h3><ol><li>（Liii STEM）接入高速版 DeepSeek V3.2，支持与公式直接交互。</li><li>极大优化数学模式编辑性能，修复 Tab Cycling 卡顿问题。</li><li>修复 Windows 在 125% 缩放等情况下菜单栏消失的问题。</li><li>表格环境支持任意角度旋转。</li><li>更改可折叠代码块的背景色。</li><li>新增下划线与删除线（可配合 Comment 插件使用）。</li></ol><h3 id="mogan-stem-v2025-2-1-2025-12-03" tabindex="-1">Mogan STEM v2025.2.1 (2025/12/03) <a class="header-anchor" href="#mogan-stem-v2025-2-1-2025-12-03" aria-label="Permalink to “Mogan STEM v2025.2.1 (2025/12/03)”">​</a></h3><ol><li>Python 插件渲染升级：Matplotlib 绘图、SymPy 公式、Pandas 表格渲染为可编辑内容；支持折叠的可运行代码块并保留源代码。</li><li>插件与环境：支持 conda 环境；完善 Maxima、Gnuplot 等插件展示与渲染体验。</li><li>格式与图片：原生支持 PDF 矢量图；新增 WebP 图片支持。</li><li>多标签页：支持多标签页置顶。</li><li>编辑器体验：光标颜色/闪烁、选中背景色等优化；页码设置更灵活。</li><li>其余更新：新增多种符号与 Tab Cycling 输入（<code>\\textendash</code>/<code>\\textemdash</code>、LEGO 符号等）；模式工具栏新增附录（Appendix）选项与快捷键。</li><li>商业版：同步发布 Liii STEM v2025.2.1（支持登录，开启公测）。</li></ol><h2 id="👏-加入社区" tabindex="-1">👏 加入社区 <a class="header-anchor" href="#👏-加入社区" aria-label="Permalink to “👏 加入社区”">​</a></h2><ul><li>墨干社区 QQ 群：934456971</li><li>Discord 群组：<a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li><li>官网：<a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li></ul>',15)])])}const b=i(t,[["render",n]]);export{m as __pageData,b as default};
